const crypto = require('crypto');
const secret = '73f0b54afa26320af143b62794ca2c4c'; // Se reemplazará por el real
const signature = $node["Webhook"].json["headers"]["x-luna-signature"];
const body = JSON.stringify($node["Webhook"].json["body"]);

const hmac = crypto.createHmac('sha256', secret);
hmac.update(body);
const expectedSignature = hmac.digest('hex');

if (signature !== expectedSignature) {
  throw new Error('Invalid HMAC Signature');
}

return { signature_valid: true, payload: $node["Webhook"].json["body"] };
